import{_ as o,o as t,c as r,ah as i}from"./chunks/framework.Bi9enVNS.js";const p=JSON.parse('{"title":"Architecture and Data Flow","description":"","frontmatter":{},"headers":[],"relativePath":"en/intro/architecture.md","filePath":"en/intro/architecture.md","lastUpdated":1774205896000}'),a={name:"en/intro/architecture.md"};function n(d,e,l,c,s,h){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="architecture-and-data-flow" tabindex="-1">Architecture and Data Flow <a class="header-anchor" href="#architecture-and-data-flow" aria-label="Permalink to &quot;Architecture and Data Flow&quot;">​</a></h1><p>VLT is intentionally a compact monolithic reference implementation. Ingestion, validation, normalization, in-memory storage, HTTP queries, and the frontend workbench all live in the same repository.</p><h2 id="end-to-end-path" tabindex="-1">End-to-end path <a class="header-anchor" href="#end-to-end-path" aria-label="Permalink to &quot;End-to-end path&quot;">​</a></h2><ol><li>A client builds an <code>ingest.v1.UploadLogsRequest</code>.</li><li>The batch is sent to <code>POST /v1/logs</code> with <code>Authorization: Bearer &lt;token&gt;</code>.</li><li>The server reads the body, handles <code>Content-Encoding</code>, and decodes by <code>Content-Type</code>.</li><li>It performs batch-level validation and then record-level validation.</li><li>Accepted records are normalized into <code>NormalizedLogRecord</code>.</li><li>Those records are written into the in-memory store.</li><li>Frontend or other clients query logs, trace detail, timeline, topology, and grouped sources.</li></ol><h2 id="main-modules" tabindex="-1">Main modules <a class="header-anchor" href="#main-modules" aria-label="Permalink to &quot;Main modules&quot;">​</a></h2><div class="vlt-source-list"><div><strong>Protocol layer</strong><span><code>proto/vlt/common/v1</code>, <code>proto/vlt/logs/v1</code>, and <code>proto/vlt/ingest/v1</code></span></div><div><strong>Ingest layer</strong><span><code>internal/ingest</code> handles decoding, validation, authorization, normalization, and idempotency caching.</span></div><div><strong>HTTP API</strong><span><code>internal/api/http.go</code> exposes ingest and query routes and applies CORS.</span></div><div><strong>Store layer</strong><span><code>internal/store/memory</code> stores normalized records and serves aggregations.</span></div></div><h2 id="core-derived-entities" tabindex="-1">Core derived entities <a class="header-anchor" href="#core-derived-entities" aria-label="Permalink to &quot;Core derived entities&quot;">​</a></h2><ul><li><code>NormalizedLogRecord</code>: the base record used by search and trace aggregation</li><li><code>TraceTimelineResponse</code>: timeline grouped by <code>source_fingerprint</code></li><li><code>TraceTopologyResponse</code>: nodes and edges derived from adjacent source segments</li><li><code>SourceGroup</code>: grouped data for the sources view</li></ul><h2 id="important-derivations" tabindex="-1">Important derivations <a class="header-anchor" href="#important-derivations" aria-label="Permalink to &quot;Important derivations&quot;">​</a></h2><ul><li>Effective source prefers <code>LogRecord.source</code>; otherwise it falls back to batch <code>default_source</code></li><li><code>source_fingerprint</code> is derived from <code>project + environment + source_type + source_name + instance_id</code></li><li>Timeline groups records by <code>source_fingerprint</code></li><li>Topology first collapses consecutive identical source segments, then emits edges from adjacent segments</li></ul><h2 id="deliberate-tradeoffs" tabindex="-1">Deliberate tradeoffs <a class="header-anchor" href="#deliberate-tradeoffs" aria-label="Permalink to &quot;Deliberate tradeoffs&quot;">​</a></h2><ul><li>In-memory storage keeps the reference implementation simple</li><li>One HTTP ingest surface keeps protocol behavior explicit</li><li>Explicit source modeling keeps the multi-source trace problem easy to reason about</li></ul><h2 id="sources-of-truth" tabindex="-1">Sources of truth <a class="header-anchor" href="#sources-of-truth" aria-label="Permalink to &quot;Sources of truth&quot;">​</a></h2><ul><li><code>internal/api/http.go</code></li><li><code>internal/ingest/decode.go</code></li><li><code>internal/ingest/normalize.go</code></li><li><code>internal/store/store.go</code></li><li><code>internal/store/memory/memory.go</code></li></ul>',14)])])}const m=o(a,[["render",n]]);export{p as __pageData,m as default};
